const { BigQuery } = require('@google-cloud/bigquery');
const functions = require('@google-cloud/functions-framework');

functions.http('aggregateData', async (req, res) => {
  const bigqueryClient = new BigQuery();

  try {
    // Validate input parameters
    if (!req.query.projectId || !req.query.datasetId || !req.query.tableId) {
      return res.status(400).send('Missing required parameters');
    }

    const projectId = req.query.projectId;
    const datasetId = req.query.datasetId;
    const tableId = req.query.tableId;

    // Construct a reference to the BigQuery dataset and table
    const dataset = bigqueryClient.dataset(datasetId);
    const table = dataset.table(tableId);

    // Query the data from BigQuery
    const options = {
      query: `SELECT * FROM \`${projectId}.${datasetId}.${tableId}\``,
      location: 'US',
    };

    const [rows] = await table.getRows(options);

    // Aggregate the data (example aggregation)
    let sum = 0;
    rows.forEach(row => {
      if (row.value) {
        sum += row.value;
      }
    });

    return res.status(200).send(`Sum of values: ${sum}`);
  } catch (error) {
    console.error('Error processing data:', error);
    return res.status(500).send('Internal Server Error');
  }
});